import Combine
import Foundation
import UIKit

// TODO: rename to CountryManager
class CountryManagerInstance: @unchecked Sendable {
    fileprivate(set) var countries: [Country]
    fileprivate let countryByCode: [String: Country]
    fileprivate let countryBySiteId: [String: Country]

    let defaultCountry: Country

    init(
        defaultCountry: Country,
        countries: [Country],
        allCountries: [Country]? = nil
    ) {
        self.countries = countries
        self.defaultCountry = defaultCountry
        let lookup = allCountries ?? countries
        countryByCode = Dictionary(uniqueKeysWithValues: lookup.map { ($0.code.lowercased(), $0) })
        countryBySiteId = Dictionary(uniqueKeysWithValues: lookup.map { ($0.siteId.lowercased(), $0) })
    }

    public var operatingCountries: [Country] {
        countries.filter { $0.isOperating }
    }

    public func countryForCode(_ code: String?) -> Country? {
        code.flatMap { countryByCode[$0.lowercased()] }
    }

    public func countryForSiteId(_ siteId: String?) -> Country? {
        siteId.flatMap { countryBySiteId[$0.lowercased()] }
    }

    public func countryForDomain(_ host: String?) -> Country? {
        countries.first(where: { $0.domain == host })
    }

    public var showCountrySelector: Bool {
        operatingCountries.count > 1
    }
}

protocol GetCountryUseCase {
    func callAsFunction() -> Country
}

struct GetCountryUseCaseImpl: GetCountryUseCase {
    private let user: User

    init(user: User) {
        self.user = user
    }

    func callAsFunction() -> Country {
        user.selectedCountry
    }
}

